from qiskit import transpile
from scipy.optimize import minimize

def run_and_analyze(circuit, aer_sim, graph):
    transpiled = transpile(circuit, aer_sim)

    def objective(params):
        binds = {circuit.parameters[i]: [params[i]] for i in range(circuit.num_parameters)}
        result = aer_sim.run(transpiled, parameter_binds=[binds], shots=1024).result()
        counts = result.get_counts()
        reversed_counts = {key[::-1]: val for key, val in counts.items()}
        return -compute_expectation(reversed_counts, graph)

    initial_params = [1.0] * circuit.num_parameters
    res = minimize(objective, initial_params, method='COBYLA', options={'maxiter': 100})

    optimal_params = res.x
    final_binds = {circuit.parameters[i]: [optimal_params[i]] for i in range(circuit.num_parameters)}
    result = aer_sim.run(transpiled, parameter_binds=[final_binds], shots=8192).result()
    counts = result.get_counts()
    reversed_counts = {key[::-1]: val for key, val in counts.items()}

    sorted_counts = sorted(reversed_counts.items(), key=lambda x: x[1], reverse=True)
    top_two = [sorted_counts[0][0], sorted_counts[1][0]]
    return top_two
"""
